using BotFramework.Discord.Commands;
using BotFramework.Discord.Routing;
using Games.Poker.Application.Services;
namespace Games.Poker.Discord;
public sealed class PokerDiscordHandler(IPokerService service):IDiscordMessageHandler{
public bool CanHandle(DiscordMessageContext c)=>DiscordCommand.Is(c,"poker");
public async Task HandleAsync(DiscordMessageContext c){var p=DiscordCommand.Parts(c);var uid=DiscordCommand.UserId(c);var scope=DiscordCommand.ScopeId(c);object? r;if(p.Length<2){var x=await service.FindMyTableAsync(uid,scope,c.CancellationToken);r=x.Snapshot;}else switch(p[1].ToLowerInvariant()){case "create":r=await service.CreateTableAsync(uid,DiscordCommand.DisplayName(c),scope,DiscordCommand.SourceId(c),c.CancellationToken);break;case "join" when p.Length>2:r=await service.JoinTableAsync(uid,DiscordCommand.DisplayName(c),scope,p[2],DiscordCommand.SourceId(c),c.CancellationToken);break;case "start":r=await service.StartHandAsync(uid,scope,c.CancellationToken);break;case "check":case "call":case "fold":r=await service.ApplyPlayerActionAsync(uid,scope,p[1],0,c.CancellationToken);break;case "raise" when p.Length>2&&int.TryParse(p[2],out var amount):r=await service.ApplyPlayerActionAsync(uid,scope,"raise",amount,c.CancellationToken);break;case "leave":r=await service.LeaveTableAsync(uid,scope,c.CancellationToken);break;case "state":var x=await service.FindMyTableAsync(uid,scope,c.CancellationToken);r=x.Snapshot;break;default:await DiscordCommand.ReplyAsync(c,"`poker create|join <code>|start|state|check|call|fold|raise <amount>|leave`");return;}await DiscordCommand.ReplyResultAsync(c,r,"Poker");}}
public static class PokerDiscordModule{public static IServiceCollection AddPokerDiscord(this IServiceCollection s)=>s.AddScoped<IDiscordMessageHandler,PokerDiscordHandler>();}
